parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "score": {
      "type": "number",
      "description": "Average of all five criterion scores rounded to 2 decimal places."
    },
    "reasoning": {
      "type": "string",
      "description": "3-5 sentences covering what each criterion scored and why, what drove the score up, what held it down, and the single most impactful improvement."
    }
  },
  "required": ["score", "reasoning"]
}
